import{_ as h,o as t,c as o,a0 as i}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Hướng dẫn sử dụng cho Công ty Thương mại","description":"","frontmatter":{"title":"Hướng dẫn sử dụng cho Công ty Thương mại"},"headers":[],"relativePath":"trading-company.md","filePath":"trading-company.md"}'),a={name:"trading-company.md"};function g(l,n,c,r,u,e){return t(),o("div",null,[...n[0]||(n[0]=[i('<h1 id="huong-dan-su-dung-cho-cong-ty-thuong-mai" tabindex="-1">Hướng dẫn sử dụng cho Công ty Thương mại <a class="header-anchor" href="#huong-dan-su-dung-cho-cong-ty-thuong-mai" aria-label="Permalink to &quot;Hướng dẫn sử dụng cho Công ty Thương mại&quot;">​</a></h1><p>Công ty thương mại mua hàng từ nhà cung cấp và bán lại cho khách hàng mà không qua sản xuất. ABNERP cung cấp đầy đủ công cụ để quản lý toàn bộ quy trình kinh doanh — từ đặt hàng, nhập kho, bán hàng, đến thu tiền và báo cáo tài chính.</p><h2 id="quy-trinh-nghiep-vu-cot-loi" tabindex="-1">Quy trình nghiệp vụ cốt lõi <a class="header-anchor" href="#quy-trinh-nghiep-vu-cot-loi" aria-label="Permalink to &quot;Quy trình nghiệp vụ cốt lõi&quot;">​</a></h2><h3 id="_1-quan-ly-danh-muc" tabindex="-1">1. Quản lý danh mục <a class="header-anchor" href="#_1-quan-ly-danh-muc" aria-label="Permalink to &quot;1. Quản lý danh mục&quot;">​</a></h3><p>Trước khi bắt đầu giao dịch, cần thiết lập các danh mục cơ bản:</p><ul><li><strong>Công ty</strong>: Thông tin pháp lý của doanh nghiệp</li><li><strong>Mặt hàng</strong>: Danh sách sản phẩm kinh doanh — có thể là một mặt hàng (sản phẩm đơn lẻ) hoặc biến thể (nhiều màu sắc/kích cỡ)</li><li><strong>Khách hàng</strong>: Thông tin khách mua hàng (bán buôn, bán lẻ)</li><li><strong>Nhà cung cấp</strong>: Thông tin đối tác cung cấp hàng hóa</li><li><strong>Sơ đồ tài khoản</strong>: Hệ thống tài khoản kế toán — ABNERP tự động tạo dựa trên quốc gia</li></ul><h3 id="_2-mua-hang-—-nhap-kho" tabindex="-1">2. Mua hàng — Nhập kho <a class="header-anchor" href="#_2-mua-hang-—-nhap-kho" aria-label="Permalink to &quot;2. Mua hàng — Nhập kho&quot;">​</a></h3><p>Quy trình mua hàng điển hình:</p><ol><li><strong>Yêu cầu mua hàng</strong> (Materials Request): Bộ phận kho đề xuất mua khi hàng sắp hết</li><li><strong>Đơn mua hàng</strong> (Purchase Order): Đặt hàng chính thức với nhà cung cấp</li><li><strong>Nhập kho</strong> (Purchase Receipt): Ghi nhận hàng về kho, kiểm tra số lượng và chất lượng</li><li><strong>Hóa đơn mua hàng</strong> (Purchase Invoice): Ghi nhận công nợ phải trả và thuế đầu vào</li></ol><blockquote><p>Mẹo: Sử dụng tính năng <strong>Tự động đặt hàng</strong> để hệ thống tự tạo đơn mua hàng khi tồn kho xuống dưới mức tối thiểu.</p></blockquote><h3 id="_3-ban-hang-—-xuat-kho" tabindex="-1">3. Bán hàng — Xuất kho <a class="header-anchor" href="#_3-ban-hang-—-xuat-kho" aria-label="Permalink to &quot;3. Bán hàng — Xuất kho&quot;">​</a></h3><p>Quy trình bán hàng điển hình:</p><ol><li><strong>Báo giá</strong> (Quotation): Gửi báo giá cho khách hàng</li><li><strong>Đơn bán hàng</strong> (Sales Order): Xác nhận đơn hàng từ khách</li><li><strong>Xuất kho</strong> (Delivery Note): Ghi nhận hàng rời khỏi kho</li><li><strong>Hóa đơn bán hàng</strong> (Sales Invoice): Ghi nhận doanh thu và công nợ phải thu</li><li><strong>Thu tiền</strong> (Payment Entry): Ghi nhận thanh toán từ khách hàng</li></ol><h3 id="_4-quan-ly-kho" tabindex="-1">4. Quản lý kho <a class="header-anchor" href="#_4-quan-ly-kho" aria-label="Permalink to &quot;4. Quản lý kho&quot;">​</a></h3><ul><li>Theo dõi tồn kho theo thời gian thực cho từng mặt hàng và từng kho</li><li>Kiểm kê định kỳ để đối chiếu thực tế và hệ thống</li><li>Chuyển kho giữa các chi nhánh hoặc kho vùng</li><li>Điều chỉnh tồn kho khi phát hiện sai lệch</li></ul><h3 id="_5-theo-doi-cong-no" tabindex="-1">5. Theo dõi công nợ <a class="header-anchor" href="#_5-theo-doi-cong-no" aria-label="Permalink to &quot;5. Theo dõi công nợ&quot;">​</a></h3><ul><li><strong>Công nợ phải thu</strong>: Theo dõi khách hàng còn nợ bao nhiêu, quá hạn bao lâu</li><li><strong>Công nợ phải trả</strong>: Theo dõi khoản cần thanh toán cho nhà cung cấp</li><li><strong>Báo cáo công nợ</strong>: Lọc theo khách hàng, nhà cung cấp, kỳ hạn</li></ul><h3 id="_6-quan-ly-gia-va-chiet-khau" tabindex="-1">6. Quản lý giá và chiết khấu <a class="header-anchor" href="#_6-quan-ly-gia-va-chiet-khau" aria-label="Permalink to &quot;6. Quản lý giá và chiết khấu&quot;">​</a></h3><ul><li><strong>Bảng giá</strong>: Thiết lập giá bán khác nhau cho từng nhóm khách hàng (bán buôn, bán lẻ, VIP)</li><li><strong>Quy tắc định giá</strong>: Tự động áp dụng chiết khấu theo số lượng, theo dịp khuyến mãi</li><li><strong>Giá mua</strong>: Theo dõi lịch sử giá mua từ từng nhà cung cấp</li></ul><h2 id="bao-cao-quan-trong" tabindex="-1">Báo cáo quan trọng <a class="header-anchor" href="#bao-cao-quan-trong" aria-label="Permalink to &quot;Báo cáo quan trọng&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Báo cáo</th><th>Mục đích</th></tr></thead><tbody><tr><td><strong>Báo cáo tồn kho</strong></td><td>Số lượng tồn, giá trị tồn kho, hàng sắp hết</td></tr><tr><td><strong>Báo cáo lợi nhuận gộp</strong></td><td>Lợi nhuận theo mặt hàng, hóa đơn, khách hàng</td></tr><tr><td><strong>Báo cáo công nợ</strong></td><td>Khoản phải thu/phải trả, tuổi nợ</td></tr><tr><td><strong>Báo cáo bán hàng</strong></td><td>Doanh thu theo ngày/tháng/năm, theo nhân viên</td></tr><tr><td><strong>Báo cáo mua hàng</strong></td><td>Chi phí mua hàng theo nhà cung cấp, theo mặt hàng</td></tr><tr><td><strong>Báo cáo tài chính</strong></td><td>Sổ cái, bảng cân đối kế toán, báo cáo thu nhập</td></tr></tbody></table><h2 id="tinh-nang-huu-ich-cho-cong-ty-thuong-mai" tabindex="-1">Tính năng hữu ích cho công ty thương mại <a class="header-anchor" href="#tinh-nang-huu-ich-cho-cong-ty-thuong-mai" aria-label="Permalink to &quot;Tính năng hữu ích cho công ty thương mại&quot;">​</a></h2><ul><li><strong>Đa kho hàng</strong>: Quản lý nhiều kho (kho trung tâm, kho chi nhánh, kho bán lẻ) với tồn kho riêng biệt</li><li><strong>Đa tiền tệ</strong>: Giao dịch với nhà cung cấp nước ngoài và khách hàng nước ngoài</li><li><strong>Đa công ty</strong>: Quản lý nhiều công ty thương mại trên cùng một hệ thống</li><li><strong>Tích hợp website</strong>: Bán hàng trực tuyến qua website tích hợp sẵn</li><li><strong>Tự động hóa</strong>: Gửi email xác nhận đơn hàng, nhắc thanh toán, thông báo tồn kho thấp</li><li><strong>Phân quyền</strong>: Nhân viên kinh doanh chỉ xem được đơn hàng và khách hàng của mình</li></ul><h2 id="cac-buoc-bat-đau" tabindex="-1">Các bước bắt đầu <a class="header-anchor" href="#cac-buoc-bat-đau" aria-label="Permalink to &quot;Các bước bắt đầu&quot;">​</a></h2><ol><li>Thiết lập <a href="/company-setup.html">Công ty</a> và các danh mục</li><li>Nhập <a href="/item.html">danh sách mặt hàng</a> và <a href="/customer.html">khách hàng</a>, <a href="/supplier.html">nhà cung cấp</a></li><li>Thiết lập <a href="/chart-of-accounts.html">sơ đồ tài khoản</a> và <a href="/opening-balance.html">số dư đầu kỳ</a></li><li>Cấu hình <a href="/pricing.html">bảng giá</a> và <a href="/stock-settings.html">thiết lập kho</a></li><li>Bắt đầu tạo đơn mua hàng và bán hàng</li></ol><h2 id="chu-đe-lien-quan" tabindex="-1">Chủ đề liên quan <a class="header-anchor" href="#chu-đe-lien-quan" aria-label="Permalink to &quot;Chủ đề liên quan&quot;">​</a></h2><ul><li><a href="/setting-up.html">Thiết lập</a> — Hướng dẫn cấu hình ban đầu</li><li><a href="/item.html">Mặt hàng</a> — Quản lý danh mục sản phẩm</li><li><a href="/stock.html">Kho</a> — Quản lý tồn kho và nhập xuất</li><li><a href="/selling.html">Bán hàng</a> — Quy trình bán hàng</li><li><a href="/buying.html">Mua hàng</a> — Quy trình mua hàng</li><li><a href="/accounts.html">Kế toán</a> — Quản lý tài chính kế toán</li><li><a href="/permissions.html">Phân quyền</a> — Thiết lập quyền truy cập cho nhân viên</li></ul>',27)])])}const m=h(a,[["render",g]]);export{d as __pageData,m as default};
